function solve(nums: number[], queries: number[][]): number[] {
    const n = nums.length;
    const ans: number[] = [];

    for (const [li, ri, threshold] of queries) {
        const freq = new Map<number, number>();
        for (let i = li; i <= ri; i++) {
            const num = nums[i];
            freq.set(num, (freq.get(num) || 0) + 1);
        }

        let maxCount = -1;
        let bestNum = -1;

        for (const [num, count] of freq.entries()) {
            if (count >= threshold) {
                if (count > maxCount || (count === maxCount && num < bestNum)) {
                    maxCount = count;
                    bestNum = num;
                }
            }
        }

        ans.push(bestNum === -1 ? -1 : bestNum);
    }

    return ans;
}

