import java.util.HashMap;
import java.util.Map;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int q = queries.length;
        long[] ans = new long[q];
        for (int i = 0; i < q; i++) {
            long li = queries[i][0];
            long ri = queries[i][1];
            long threshold = queries[i][2];
            Map<Long, Integer> freq = new HashMap<>();
            for (int j = (int) li; j <= (int) ri; j++) {
                long num = nums[j];
                freq.put(num, freq.getOrDefault(num, 0) + 1);
            }
            int maxCount = -1;
            long bestNum = -1;
            for (Map.Entry<Long, Integer> entry : freq.entrySet()) {
                long num = entry.getKey();
                int count = entry.getValue();
                if (count >= threshold) {
                    if (count > maxCount || (count == maxCount && num < bestNum)) {
                        maxCount = count;
                        bestNum = num;
                    }
                }
            }
            ans[i] = bestNum == -1 ? -1 : bestNum;
        }
        return ans;
    }
}
