import java.util.HashMap;
import java.util.Map;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        long[] ans = new long[queries.length];

        for (int i = 0; i < queries.length; i++) {
            long li = queries[i][0];
            long ri = queries[i][1];
            long threshold = queries[i][2];

            Map<Long, Long> freq = new HashMap<>();
            for (int j = (int) li; j <= (int) ri; j++) {
                long num = nums[j];
                freq.put(num, freq.getOrDefault(num, 0L) + 1);
            }

            long maxCount = -1;
            long bestNum = -1;

            for (Map.Entry<Long, Long> entry : freq.entrySet()) {
                long num = entry.getKey();
                long count = entry.getValue();
                if (count >= threshold) {
                    if (count > maxCount || (count == maxCount && num < bestNum)) {
                        maxCount = count;
                        bestNum = num;
                    }
                }
            }

            ans[i] = bestNum == -1 ? -1 : bestNum;
        }

        return ans;
    }
}
